import mongoose, { Document, Schema } from 'mongoose';

interface Group extends Document {
  name: string;
  description: string;
  adminId: mongoose.Types.ObjectId;
  members: mongoose.Types.ObjectId[];
  telegramChatId?: string;
  createdAt: Date;
}

const GroupSchema: Schema = new Schema({
  name: { type: String, required: true },
  description: { type: String, required: true },
  adminId: { type: mongoose.Types.ObjectId, required: true, ref: 'User' },
  members: [{ type: mongoose.Types.ObjectId, ref: 'User' }],
  telegramChatId: { type: String },
  createdAt: { type: Date, default: Date.now }
});

export default mongoose.model<Group>('Group', GroupSchema);

import GroupModel from './group.model';
import { Types } from 'mongoose';

class GroupRepository {
  async create(groupData: any): Promise<any> {
    const group = new GroupModel(groupData);
    return await group.save();
  }

  async findById(id: string): Promise<any> {
    return await GroupModel.findById(new Types.ObjectId(id));
  }

  async addTelegramChat(id: string, telegramChatId: string): Promise<any> {
    return await GroupModel.findByIdAndUpdate(
      new Types.ObjectId(id),
      { telegramChatId },
      { new: true }
    );
  }

  // Pagination could be implemented when fetching all groups
  async findAll(): Promise<any> {
    return await GroupModel.find();
  }
}

export default new GroupRepository();

import groupRepository from './group.repository';
import { BadRequestError } from '../errors'; // Custom error class

class GroupService {
  async createGroup(name: string, description: string, adminId: string): Promise<any> {
    if (!name || !description || !adminId) {
      throw new BadRequestError('Invalid group data');
    }
    return await groupRepository.create({ name, description, adminId: new Types.ObjectId(adminId) });
  }

  async getGroup(groupId: string): Promise<any> {
    const group = await groupRepository.findById(groupId);
    if (!group) {
      throw new BadRequestError('Group not found');
    }
    return group;
  }

  async linkTelegram(groupId: string, telegramChatId: string): Promise<any> {
    if (!telegramChatId) {
      throw new BadRequestError('Invalid Telegram Chat ID');
    }
    return await groupRepository.addTelegramChat(groupId, telegramChatId);
  }
}

export default new GroupService();

import { Request, Response, NextFunction } from 'express';
import groupService from './group.service';
import { zodValidateGroupCreate } from './group.validator';

class GroupController {
  async createGroup(req: Request, res: Response, next: NextFunction): Promise<void> {
    try {
      const { name, description } = req.body;
      const adminId = req.user.id; // assuming JWT Middleware adds `user` to req
      zodValidateGroupCreate(req.body);
      const group = await groupService.createGroup(name, description, adminId);
      res.status(201).json({ success: true, data: group });
    } catch (error) {
      next(error);
    }
  }

  async getGroup(req: Request, res: Response, next: NextFunction): Promise<void> {
    try {
      const groupId = req.params.id;
      const group = await groupService.getGroup(groupId);
      res.json({ success: true, data: group });
    } catch (error) {
      next(error);
    }
  }

  async linkTelegram(req: Request, res: Response, next: NextFunction): Promise<void> {
    try {
      const groupId = req.params.id;
      const { telegramChatId } = req.body;
      const group = await groupService.linkTelegram(groupId, telegramChatId);
      res.json({ success: true, data: group });
    } catch (error) {
      next(error);
    }
  }
}

export default new GroupController();

import { z } from 'zod';

export const groupCreateSchema = z.object({
  name: z.string().min(1, "Name is required"),
  description: z.string().min(1, "Description is required"),
});

export function zodValidateGroupCreate(data: any): void {
  groupCreateSchema.parse(data);
}

export interface GroupCreateDTO {
  name: string;
  description: string;
  adminId: string;
}

export interface GroupResponseDTO {
  id: string;
  name: string;
  description: string;
  adminId: string;
  members: string[];
  telegramChatId?: string;
  createdAt: Date;
}
